"use strict";(self.webpackChunkwangdoc=self.webpackChunkwangdoc||[]).push([[9906],{65629:(n,s,e)=>{e.r(s),e.d(s,{data:()=>a});const a={key:"v-201aed8f",path:"/git-tutorial/commands/git-reset.html",title:"git reset",lang:"zh-CN",frontmatter:{summary:"git reset git reset命令用于将当前分支指向另一个位置。 如果不指定回滚的位置，那么等同于撤销修改。 参数 soft: 不改变工作区和缓存区，只移动 HEAD 到指定 commit。; mixed: 只改变缓存区，不改变工作区。这是默认参数，通常用于撤销git add。; hard：改变工作区和暂存区到指定 commit。该参数等同于重置，可",head:[["meta",{property:"og:url",content:"https://yzqbooks.github.io/wangdoc/wangdoc/git-tutorial/commands/git-reset.html"}],["meta",{property:"og:site_name",content:"wangdoc"}],["meta",{property:"og:title",content:"git reset"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-06T10:09:00.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:modified_time",content:"2022-04-06T10:09:00.000Z"}]]},excerpt:"",headers:[{level:2,title:"参数",slug:"参数",children:[]}],git:{createdTime:164923974e4,updatedTime:164923974e4,contributors:[{name:"yzqdev",email:"yzqdev@outlook.com",commits:1}]},readingTime:{minutes:1.28,words:385},filePathRelative:"git-tutorial/commands/git-reset.md"}},68114:(n,s,e)=>{e.r(s),e.d(s,{default:()=>r});const a=(0,e(66252).uE)('<h1 id="git-reset" tabindex="-1"><a class="header-anchor" href="#git-reset" aria-hidden="true">#</a> git reset</h1><p><code>git reset</code>命令用于将当前分支指向另一个位置。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 将当期分支的指针倒退三个 commit，</span>\n<span class="token comment"># 并且会改变暂存区</span>\n$ <span class="token function">git</span> reset HEAD~3\n\n<span class="token comment"># 倒退指针的同时，不改变暂存区</span>\n$ <span class="token function">git</span> reset --soft HEAD~3\n\n<span class="token comment"># 倒退指针的同时，改变工作区</span>\n$ <span class="token function">git</span> reset --hard HEAD~3\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>如果不指定回滚的位置，那么等同于撤销修改。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 撤销上一次向暂存区添加的所有文件</span>\n$ <span class="token function">git</span> reset\n\n<span class="token comment"># 无任何效果</span>\n$ <span class="token function">git</span> reset --soft\n\n<span class="token comment"># 同时撤销暂存区和工作区的修改，</span>\n<span class="token comment"># 回复到上一次提交的状态</span>\n$ <span class="token function">git</span> reset --hard\n\n<span class="token comment"># 撤销上一次向暂存区添加的某个指定文件，</span>\n<span class="token comment"># 不影响工作区中的该文件</span>\n$ <span class="token function">git</span> reset -- <span class="token operator">&lt;</span>filename<span class="token operator">&gt;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li>soft: 不改变工作区和缓存区，只移动 HEAD 到指定 commit。</li><li>mixed: 只改变缓存区，不改变工作区。这是默认参数，通常用于撤销<code>git add</code>。</li><li>hard：改变工作区和暂存区到指定 commit。该参数等同于重置，可能会引起数据损失。<code>git reset --hard</code>等同于<code>git reset --hard HEAD</code>。</li><li><code>-p</code>表示键入交互模式，指定暂存区的哪些部分需要撤销。</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># Undo add</span>\n$ <span class="token function">git</span> reset\n\n<span class="token comment"># Undo a commit，不重置工作区和缓存区</span>\n<span class="token comment"># 回到 HEAD 之前的那个 commit</span>\n$ <span class="token function">git</span> reset --soft HEAD^\n\n<span class="token comment"># Undo a commit，重置工作区和缓存区</span>\n<span class="token comment"># 连续撤销三个 commit：HEAD, HEAD^, and HEAD~2</span>\n$ <span class="token function">git</span> reset --hard HEAD~3\n\n<span class="token comment"># 从暂存区移除指定文件，但不改变工作区中的该文件</span>\n$ <span class="token function">git</span> reset -- frotz.c\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div>',8),t={},r=(0,e(83744).Z)(t,[["render",function(n,s){return a}]])},83744:(n,s)=>{s.Z=(n,s)=>{const e=n.__vccOpts||n;for(const[n,a]of s)e[n]=a;return e}}}]);